import { NextRequest, NextResponse } from 'next/server';

const VC_API_BASE_URL =
  process.env.NEXT_PUBLIC_VC_SIM_API_BASE_URL?.replace(/\/$/, '') || 'http://localhost:8000';

function normalizeDomain(domainInput: string): string {
  return domainInput
    .trim()
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/\/.*$/, '');
}

export async function GET(request: NextRequest) {
  const domainInput = request.nextUrl.searchParams.get('domain') || '';
  const domain = normalizeDomain(domainInput);
  if (!domain) {
    return NextResponse.json({ error: 'domain is required' }, { status: 400 });
  }

  try {
    const upstream = await fetch(
      `${VC_API_BASE_URL}/api/v1/investors/search?domain=${encodeURIComponent(domain)}`,
      { cache: 'no-store' }
    );

    if (!upstream.ok) {
      return NextResponse.json(
        {
          status: 'error',
          source: 'proxy_error',
          domain,
          upstream_status: upstream.status,
          investor_context: null,
        },
        { status: upstream.status }
      );
    }

    const payload = await upstream.json();
    return NextResponse.json(
      {
        status: 'ok',
        source: payload?.source || 'unknown',
        domain,
        investor_context: {
          profile: payload?.profile || null,
          portfolio_companies: payload?.portfolio_companies || [],
          query_contract: payload?.query_contract || {},
          source: payload?.source || 'unknown',
        },
      },
      { status: 200 }
    );
  } catch (error) {
    return NextResponse.json(
      {
        status: 'error',
        source: 'proxy_exception',
        domain,
        message: error instanceof Error ? error.message : 'unknown error',
        investor_context: null,
      },
      { status: 502 }
    );
  }
}
